css:
.wrapper .rt-ksnap {
  --rt-surface: var(--block-bg-color, #15151A);
  --rt-surface-raised: #1B1B22;
  --rt-ink: var(--color-text, #F4F4F7);
  --rt-muted: var(--color-gray-500, #8A8A96);
  --rt-line: var(--color-gray-200, rgba(255,255,255,.07));
  --rt-accent: var(--color-primary, #FFD21E);
  --rt-accent-2: var(--color-secondary, #FF3D8B);
  --rt-success: var(--color-success, #36D399);
  --rt-warn: #F6C453;
  --rt-danger: var(--color-danger, #FF5A6E);
  container-type: inline-size;
  width: 100%;
  box-sizing: border-box;
  color: var(--rt-ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
}
.wrapper .rt-ksnap .rt-ksnap-grid {
  display: grid;
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: 14px;
}
.wrapper .rt-ksnap .rt-kcard {
  position: relative;
  min-width: 0;
  box-sizing: border-box;
  background: var(--rt-surface);
  border: 1px solid var(--rt-line);
  border-radius: 14px;
  padding: 16px 16px 17px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: background-color .15s ease, border-color .15s ease, box-shadow .15s ease;
}
.wrapper .rt-ksnap .rt-klabel {
  display: flex;
  align-items: center;
  gap: 7px;
  min-width: 0;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--rt-muted);
  overflow-wrap: anywhere;
}
.wrapper .rt-ksnap .rt-klabel::before {
  content: "";
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--rt-accent);
  flex: 0 0 auto;
}
.wrapper .rt-ksnap .rt-kvalue {
  font: 800 26px/1.1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  font-variant-numeric: tabular-nums;
  color: var(--rt-ink);
  margin-top: 10px;
  overflow-wrap: anywhere;
}
.wrapper .rt-ksnap .rt-kctx {
  font: 600 11px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--rt-muted);
  margin-top: 5px;
  min-height: 15px;
}
.wrapper .rt-ksnap .rt-kcard.is-hero {
  background: linear-gradient(180deg, color-mix(in srgb, var(--rt-accent) 7%, var(--rt-surface)), var(--rt-surface));
  border-color: color-mix(in srgb, var(--rt-accent) 38%, var(--rt-line));
  box-shadow: 0 1px 0 rgba(255,255,255,.04) inset, 0 6px 18px rgba(0,0,0,.5), 0 0 24px -6px color-mix(in srgb, var(--rt-accent) 60%, transparent);
}
.wrapper .rt-ksnap .rt-kcard.is-hero::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  border-radius: 14px 14px 0 0;
  background: linear-gradient(90deg, var(--rt-accent), var(--rt-accent-2));
}
.wrapper .rt-ksnap .rt-kcard.is-hero .rt-kvalue { color: var(--rt-accent); }
.wrapper .rt-ksnap .rt-kcard.rt-alert.is-good .rt-klabel::before { background: var(--rt-success); }
.wrapper .rt-ksnap .rt-kcard.rt-alert.is-warn .rt-klabel::before { background: var(--rt-warn); }
.wrapper .rt-ksnap .rt-kcard.rt-alert.is-bad .rt-klabel::before { background: var(--rt-danger); }
.wrapper .rt-ksnap .rt-kcard.rt-alert.is-warn .rt-kvalue { color: var(--rt-warn); }
.wrapper .rt-ksnap .rt-kcard.rt-alert.is-bad .rt-kvalue { color: var(--rt-danger); }
.wrapper .rt-ksnap .rt-kcard.rt-alert.is-bad {
  border-color: color-mix(in srgb, var(--rt-danger) 30%, var(--rt-line));
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5), 0 0 22px -8px color-mix(in srgb, var(--rt-danger) 45%, transparent);
}
.wrapper .rt-ksnap .rt-kcard:not(.is-hero):hover { background: var(--rt-surface-raised); }
.wrapper .rt-ksnap .rt-kcard:not(.is-hero):not(.rt-alert):hover {
  border-color: color-mix(in srgb, var(--rt-accent) 35%, var(--rt-line));
}
.wrapper .rt-ksnap .rt-kcard.is-hero:hover {
  box-shadow: 0 1px 0 rgba(255,255,255,.04) inset, 0 8px 20px rgba(0,0,0,.55), 0 0 30px -6px color-mix(in srgb, var(--rt-accent) 66%, transparent);
}
.wrapper .rt-ksnap .rt-kcard:focus-visible {
  outline: 2px solid var(--rt-accent);
  outline-offset: 2px;
}
@media (prefers-reduced-motion: reduce) {
  .wrapper .rt-ksnap .rt-kcard { transition: none; }
}
@container (max-width: 1100px) {
  .wrapper .rt-ksnap .rt-ksnap-grid { grid-template-columns: repeat(3, minmax(0, 1fr)); }
}
@container (max-width: 640px) {
  .wrapper .rt-ksnap .rt-ksnap-grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }
  .wrapper .rt-ksnap .rt-kvalue { font-size: 22px; }
}
@container (max-width: 380px) {
  .wrapper .rt-ksnap .rt-ksnap-grid { grid-template-columns: minmax(0, 1fr); }
}
